mapper.select:
SELECT noti_cont.notification_content_id, noti_cont.notification_id, noti_cont.content, noti_cont.locale, noti_cont.created_date, noti_cont.created_by, noti_cont.update_date, noti_cont.update_by FROM notification noti INNER JOIN notification_content noti_cont ON noti.notification_id = noti_cont.notification_id WHERE noti.logic_del_flg != true
AND noti_cont.locale = #{locale.value}
ORDER BY notification_id
OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY
;

SELECT COUNT(*) FROM notification noti INNER JOIN notification_content noti_cont ON noti.notification_id = noti_cont.notification_id WHERE noti.logic_del_flg != true
AND noti_cont.locale = #{locale.value}
;

mapper.insert:
INSERT INTO notification (
  notification_id,
  logic_del_flg
)
VALUES (
         #{notificationId},
         #{logicDelFlg}
       )
